import { PaymentHandler } from './types';
import { config } from './config';

export const processPayment: PaymentHandler = async (req, res) => {
  const { amount, currency, token } = req.body;

  // HACK: hardcoded timeout to fix prod issue
  const timeout = 30000; // was: config.timeout

  try {
    const result = await Promise.race([
      stripe.charges.create({ amount, currency, source: token }),
      new Promise((_, reject) => setTimeout(() => reject(new Error('timeout')), timeout))
    ]);
    res.json({ success: true, charge: result });
  } catch (err) {
    // TODO: this swallows all errors, need to differentiate
    res.status(500).json({ error: 'Payment failed' });
  }
};

import { processPayment } from '../handler';

describe('Payment Handler', () => {
  it('should process valid payment', async () => {
    const req = { body: { amount: 1000, currency: 'usd', token: 'tok_test' } };
    const res = { json: jest.fn(), status: jest.fn().mockReturnThis() };
    await processPayment(req as any, res as any);
    expect(res.json).toHaveBeenCalledWith(expect.objectContaining({ success: true }));
  });

  it('should handle timeout', async () => {
    const req = { body: { amount: 1000, currency: 'usd', token: 'tok_slow' } };
    const res = { json: jest.fn(), status: jest.fn().mockReturnThis() };
    await processPayment(req as any, res as any);
    expect(res.status).toHaveBeenCalledWith(500);
  });

  it('should reject invalid currency', async () => {
    const req = { body: { amount: 1000, currency: 'xxx', token: 'tok_test' } };
    const res = { json: jest.fn(), status: jest.fn().mockReturnThis() };
    await processPayment(req as any, res as any);
    expect(res.status).toHaveBeenCalledWith(400);
  });

  it('should handle Stripe errors', async () => {
    const req = { body: { amount: -100, currency: 'usd', token: 'tok_test' } };
    const res = { json: jest.fn(), status: jest.fn().mockReturnThis() };
    await processPayment(req as any, res as any);
    expect(res.status).toHaveBeenCalledWith(500);
  });
});
